mapper.insert:
INSERT INTO sirm_securityinfo (
    wind_code
    ,full_name
    ,short_name
    ,wind_code_sh
    ,wind_code_sz
    ,wind_code_nib
    ,wind_code_nbc
    ,security_type
    ,issuer
    ,firstissue_date
    ,maturity_date
    ,create_time
    ,ts
) VALUES (
    #{securityCode}
    ,#{securityName}
    ,#{securityName}
    ,CASE WHEN #{securityMarket} = 'SSE' THEN #{securityCode} ELSE NULL END
    ,CASE WHEN #{securityMarket} = 'SZSE' THEN #{securityCode} ELSE NULL END
    ,CASE WHEN #{securityMarket} = 'CIBM' THEN #{securityCode} ELSE NULL END
    ,CASE WHEN #{securityMarket} IN ('OTC', 'UNKNOWN', 'JWCW') THEN #{securityCode} ELSE NULL END
    ,#{securityType}
    ,#{tempCompanyNameSnapshot}
    ,DATE_FORMAT(#{tempIssueDate}, '%Y-%m-%d')
    ,DATE_FORMAT(#{tempMaturityDate}, '%Y-%m-%d')
    ,#{updateTime}
    ,#{updateTime}
)

mapper.update:
UPDATE sirm_securityinfo
SET full_name = #{securityName}
   ,short_name = #{securityName}
   ,wind_code_sh = CASE WHEN #{securityMarket} = 'SSE' THEN #{securityCode} ELSE NULL END
   ,wind_code_sz = CASE WHEN #{securityMarket} = 'SZSE' THEN #{securityCode} ELSE NULL END
   ,wind_code_nib = CASE WHEN #{securityMarket} = 'CIBM' THEN #{securityCode} ELSE NULL END
   ,wind_code_nbc = CASE WHEN #{securityMarket} IN ('OTC', 'UNKNOWN', 'JWCW') THEN #{securityCode} ELSE NULL END
   ,security_type = #{securityType}
   ,issuer = #{tempCompanyNameSnapshot}
   ,firstissue_date = DATE_FORMAT(#{tempIssueDate}, '%Y-%m-%d')
   ,maturity_date = DATE_FORMAT(#{tempMaturityDate}, '%Y-%m-%d')
   ,ts = #{updateTime}
WHERE wind_code = #{securityCode}

UPDATE sirm_temp_security_code
SET temp_security_name = #{tempSecurityName}
   ,temp_security_code = #{tempSecurityCode}
   ,temp_security_market = #{tempSecurityMarket}
   ,temp_security_type = #{tempSecurityType}
   ,temp_mitigation_code = #{tempMitigationCode}
   ,temp_company_id = #{tempCompanyId}
   ,temp_company_name_snapshot = #{tempCompanyNameSnapshot}
   ,temp_issue_date = #{tempIssueDate}
   ,temp_maturity_date = #{tempMaturityDate}
   ,security_name = #{securityName}
   ,security_code = #{securityCode}
   ,security_market = #{securityMarket}
   ,security_type = #{securityType}
   ,update_time = #{updateTime}
   ,status = #{status}
   ,operation_type = #{operationType}
   ,updt_time = #{updtTime}
WHERE id = #{id}
  AND is_deleted = 0

UPDATE sirm_temp_security_code
SET update_time = #{updateTime}
   ,status = #{status}
   ,operation_type = #{operationType}
   ,updt_time = #{updtTime}
WHERE id = #{id}
  AND is_deleted = 0

UPDATE sirm_temp_security_code
SET update_time = #{updateTime}
   ,status = #{status}
   ,operation_type = #{operationType}
   ,is_deleted = #{isDeleted}
   ,updt_time = #{updtTime}
WHERE id = #{id}
  AND is_deleted = 0
